-- tambahin timezone default now
-- periksa created_at kalo belom ada
-- tambahin table prefix counters
-- table pivot many to many crew dan crew_skills

CREATE TABLE "profiles" (
  user_uuid uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  "role" text NOT NULL DEFAULT 'user',
  "avatar_url" text,
  "full_name" text NOT NULL,
  "phone" varchar UNIQUE ,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  "updated_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "location_tags" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "name" text UNIQUE NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "location_tag" (
  "location_tag_id" integer NOT NULL,
  "location_id" integer NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  PRIMARY KEY ("location_tag_id", "location_id")
);

CREATE TABLE "location_images" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "location_id" integer NOT NULL,
  "url" text NOT NULL,
  "position" integer NOT NULL DEFAULT 0
);

CREATE TABLE "locations" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "uuid" uuid UNIQUE NOT NULL,
  "code" text UNIQUE NOT NULL,
  "name" text NOT NULL,
  "description" text,
  "city" text,
  "price" integer NOT NULL DEFAULT 0,
  "area" integer,
  "pax" integer,
  "is_available" boolean NOT NULL DEFAULT true,
  "updated_at" timestamptz NOT NULL DEFAULT (now()),
  "rating" integer
);

CREATE TABLE "crews" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "uuid" uuid UNIQUE NOT NULL,
  "code" text UNIQUE NOT NULL,
  "name" text NOT NULL,
  "description" text,
  "price" integer NOT NULL DEFAULT 0,
  "is_available" boolean NOT NULL DEFAULT true,
  "updated_at" timestamptz NOT NULL DEFAULT (now()),
  "created_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "rentals" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "uuid" uuid UNIQUE NOT NULL,
  "code" text UNIQUE NOT NULL,
  "name" text NOT NULL,
  "description" text,
  "price" integer NOT NULL DEFAULT 0,
  "specifications" jsonb,
  "is_available" boolean NOT NULL DEFAULT true,
  "updated_at" timestamptz NOT NULL DEFAULT (now()),
  "created_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "expendables" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "uuid" uuid UNIQUE NOT NULL,
  "code" text UNIQUE NOT NULL,
  "name" text NOT NULL,
  "description" text,
  "price" integer NOT NULL DEFAULT 0,
  "is_available" boolean NOT NULL DEFAULT true,
  "updated_at" timestamptz NOT NULL DEFAULT (now()),
  "created_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "food_and_beverage" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "uuid" uuid UNIQUE NOT NULL,
  "code" text UNIQUE NOT NULL,
  "name" text NOT NULL,
  "description" text,
  "price" integer NOT NULL DEFAULT 0,
  "images" text[],
  "is_available" boolean NOT NULL DEFAULT true,
  "updated_at" timestamptz NOT NULL DEFAULT (now()),
  "created_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "food_and_beverage_tags" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "name" text UNIQUE NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "food_and_beverage_tag" (
  "food_and_beverage_tag_id" integer NOT NULL,
  "food_and_beverage_id" integer NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  PRIMARY KEY ("food_and_beverage_tag_id", "food_and_beverage_id")
);

CREATE TABLE "location_embeddings" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "location_id" integer NOT NULL,
  "content" jsonb NOT NULL,
  "embedding" public.vector NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "location_reviews" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "uuid" uuid UNIQUE NOT NULL,
  "user_uuid" uuid NOT NULL,
  "location_id" integer NOT NULL,
  "rating" integer NOT NULL,
  "comment" text,
  "order_id" integer NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "promo_codes" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "code" text UNIQUE NOT NULL,
  "discount_type" text NOT NULL,
  "discount_value" integer NOT NULL DEFAULT 0,
  "max_usage" integer,
  "usage_count" integer NOT NULL DEFAULT 0,
  "max_usage_per_user" integer,
  "min_order_amount" integer NOT NULL DEFAULT 0,
  "starts_at" timestamptz,
  "expires_at" timestamptz,
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  "updated_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "bundles" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "uuid" uuid UNIQUE NOT NULL,
  "name" text NOT NULL,
  "description" text,
  "is_active" boolean NOT NULL DEFAULT true,
  "base_price" integer NOT NULL DEFAULT 0,
  "discount_type" text,
  "discount_value" integer NOT NULL DEFAULT 0,
  "final_price" integer NOT NULL DEFAULT 0,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  "updated_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "bundle_crews" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "uuid" uuid UNIQUE NOT NULL,
  "bundle_id" integer NOT NULL,
  "crew_id" integer NOT NULL,
  "quantity" integer NOT NULL DEFAULT 1,
  "notes" text,
  "created_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "bundle_rentals" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "uuid" uuid UNIQUE NOT NULL,
  "bundle_id" integer NOT NULL,
  "rental_id" integer NOT NULL,
  "quantity" integer NOT NULL DEFAULT 1,
  "notes" text,
  "created_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "bundle_food_and_beverages" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "uuid" uuid UNIQUE NOT NULL,
  "bundle_id" integer NOT NULL,
  "food_and_beverage_id" integer NOT NULL,
  "quantity" integer NOT NULL DEFAULT 1,
  "notes" text,
  "created_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "bundle_expendables" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "uuid" uuid UNIQUE NOT NULL,
  "bundle_id" integer NOT NULL,
  "expendable_id" integer NOT NULL,
  "quantity" integer NOT NULL DEFAULT 1,
  "notes" text,
  "created_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "crew_skills" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "name" text NOT NULL,
  "description" text,
  "created_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "orders" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "uuid" uuid UNIQUE NOT NULL,
  "code" text UNIQUE NOT NULL,
  "user_uuid" uuid NOT NULL,
  "purpose" text NOT NULL,
  "shooting_address" text NOT NULL,
  "payment_status" text NOT NULL DEFAULT 'pending',
  "subtotal_amount" integer NOT NULL DEFAULT 0,
  "bundle_discount_amount" integer NOT NULL DEFAULT 0,
  "promo_discount_amount" integer NOT NULL DEFAULT 0,
  "total_discount_amount" integer NOT NULL DEFAULT 0,
  "grand_total_amount" integer NOT NULL DEFAULT 0,
  "promo_code_id" integer,
  "promo_code_snapshot" text,
  "promo_discount_type_snapshot" text,
  "promo_discount_value_snapshot" integer,
  "midtrans_token" text,
  "midtrans_expired_at" timestamptz,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  "updated_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "order_items" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "uuid" uuid UNIQUE NOT NULL,
  "order_id" integer NOT NULL,
  "item_type" text NOT NULL,
  "item_id" integer NOT NULL,
  "item_name_snapshot" text,
  "quantity" integer NOT NULL DEFAULT 1,
  "unit_price_snapshot" integer NOT NULL DEFAULT 0,
  "line_total" integer NOT NULL DEFAULT 0,
  "is_from_bundle" boolean NOT NULL DEFAULT false,
  "bundle_id" integer,
  "booking_start" date,
  "booking_end" date,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  "updated_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "crew_images" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "crew_id" integer NOT NULL,
  "url" text NOT NULL,
  "position" integer NOT NULL DEFAULT 0
);

CREATE TABLE "expendable_images" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "expendable_id" integer NOT NULL,
  "url" text NOT NULL,
  "position" integer NOT NULL DEFAULT 0
);

CREATE TABLE "food_and_beverage_images" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "food_and_beverage_id" integer NOT NULL,
  "url" text NOT NULL,
  "position" integer NOT NULL DEFAULT 0
);

CREATE TABLE "rental_images" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "rental_id" integer NOT NULL,
  "url" text NOT NULL,
  "position" integer NOT NULL DEFAULT 0
);

CREATE TABLE "item_categories" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "name" text,
  "short_code" text,
  "created_at" timestamptz
);

CREATE TABLE "item_sub_categories" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "name" text,
  "short_code" text,
  "created_at" timestamptz
);

CREATE TABLE "bundle_types" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "name" text,
  "short_code" text,
  "created_at" timestamptz
);

CREATE TABLE "bundle_categories" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
  "name" text,
  "short_code" text,
  "created_at" timestamptz
);

CREATE TABLE "location_item_category" (
  "location_id" integer NOT NULL,
  "item_category_id" integer NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  PRIMARY KEY ("location_id", "item_category_id")
);

CREATE TABLE "rental_item_category" (
  "rental_id" integer NOT NULL,
  "item_category_id" integer NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
