);

CREATE TABLE "expendable_item_category" (
  "expendable_id" integer NOT NULL,
  "item_category_id" integer NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  PRIMARY KEY ("expendable_id", "item_category_id")
);

CREATE TABLE "food_and_beverage_item_category" (
  "food_and_beverage_id" integer NOT NULL,
  "item_category_id" integer NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  PRIMARY KEY ("food_and_beverage_id", "item_category_id")
);

CREATE TABLE "crew_item_category" (
  "crew_id" integer NOT NULL,
  "item_category_id" integer NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  PRIMARY KEY ("crew_id", "item_category_id")
);

CREATE TABLE "location_item_sub_category" (
  "location_id" integer NOT NULL,
  "item_sub_category_id" integer NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  PRIMARY KEY ("location_id", "item_sub_category_id")
);

CREATE TABLE "rental_item_sub_category" (
  "rental_id" integer NOT NULL,
  "item_sub_category_id" integer NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
