);

CREATE TABLE "expendable_item_sub_category" (
  "expendable_id" integer NOT NULL,
  "item_sub_category_id" integer NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  PRIMARY KEY ("expendable_id", "item_sub_category_id")
);

CREATE TABLE "food_and_beverage_item_sub_category" (
  "food_and_beverage_id" integer NOT NULL,
  "item_sub_category_id" integer NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  PRIMARY KEY ("food_and_beverage_id", "item_sub_category_id")
);

CREATE TABLE "crew_item_sub_category" (
  "crew_id" integer NOT NULL,
  "item_sub_category_id" integer NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  PRIMARY KEY ("crew_id", "item_sub_category_id")
);

CREATE TABLE "bundle_type" (
  "bundle_id" integer NOT NULL,
  "bundle_type_id" integer NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  PRIMARY KEY ("bundle_id", "bundle_type_id")
);

CREATE TABLE "bundle_category" (
  "bundle_id" integer NOT NULL,
  "bundle_category_id" integer NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  PRIMARY KEY ("bundle_id", "bundle_category_id")
);

