COMMENT ON TABLE "profiles" IS 'Menyimpan informasi detail user; terhubung ke auth.users via uuid';

COMMENT ON COLUMN "profiles"."user_uuid" IS 'Primary key, reference ke auth.users.id';

COMMENT ON COLUMN "profiles"."role" IS 'Role user: user/admin';

COMMENT ON COLUMN "profiles"."avatar_url" IS 'URL avatar user';

COMMENT ON COLUMN "profiles"."full_name" IS 'Nama lengkap user';

COMMENT ON COLUMN "profiles"."phone" IS 'Nomor telepon user';

COMMENT ON COLUMN "profiles"."created_at" IS 'Waktu dibuat';

COMMENT ON COLUMN "profiles"."updated_at" IS 'Waktu diperbarui';

COMMENT ON TABLE "location_tags" IS 'Master tag untuk location';

COMMENT ON COLUMN "location_tags"."id" IS 'Primary key tag';

COMMENT ON COLUMN "location_tags"."name" IS 'Nama tag location';

COMMENT ON COLUMN "location_tags"."created_at" IS 'Waktu dibuat';

COMMENT ON TABLE "location_tag" IS 'Table pivot many-to-many antara location_tags dan locations';

COMMENT ON COLUMN "location_tag"."location_tag_id" IS 'FK ke location_tags.id';

COMMENT ON COLUMN "location_tag"."location_id" IS 'FK ke locations.id';

COMMENT ON COLUMN "location_tag"."created_at" IS 'Waktu asosiasi dibuat';

COMMENT ON TABLE "location_images" IS 'Menampung gambar location';

COMMENT ON COLUMN "location_images"."id" IS 'Primary key gambar';

COMMENT ON COLUMN "location_images"."location_id" IS 'FK ke locations.id';

COMMENT ON COLUMN "location_images"."url" IS 'URL gambar';

COMMENT ON COLUMN "location_images"."position" IS 'Urutan gambar';

COMMENT ON TABLE "locations" IS 'Master data shooting location';

COMMENT ON COLUMN "locations"."id" IS 'Primary key location';

COMMENT ON COLUMN "locations"."uuid" IS 'ID publik location';

COMMENT ON COLUMN "locations"."code" IS 'Kode location';

COMMENT ON COLUMN "locations"."name" IS 'Nama location';

COMMENT ON COLUMN "locations"."description" IS 'Deskripsi location';

COMMENT ON COLUMN "locations"."city" IS 'Kota location';

COMMENT ON COLUMN "locations"."price" IS 'Harga dasar location';

COMMENT ON COLUMN "locations"."area" IS 'Luas area';

COMMENT ON COLUMN "locations"."pax" IS 'Kapasitas orang';

COMMENT ON COLUMN "locations"."is_available" IS 'Status ketersediaan';

COMMENT ON COLUMN "locations"."updated_at" IS 'Waktu diperbarui';

COMMENT ON COLUMN "locations"."rating" IS 'Rating agregat';

COMMENT ON TABLE "crews" IS 'Master data kru produksi';

COMMENT ON COLUMN "crews"."id" IS 'Primary key crew';

COMMENT ON COLUMN "crews"."uuid" IS 'ID publik crew';

COMMENT ON COLUMN "crews"."code" IS 'Kode crew';

COMMENT ON COLUMN "crews"."name" IS 'Nama crew';

COMMENT ON COLUMN "crews"."description" IS 'Deskripsi crew';

COMMENT ON COLUMN "crews"."price" IS 'Harga per crew';

COMMENT ON COLUMN "crews"."skills" IS 'Daftar skill crew';

COMMENT ON COLUMN "crews"."images" IS 'Legacy kolom gambar; pertimbangkan pakai crew_images';

COMMENT ON COLUMN "crews"."is_available" IS 'Status ketersediaan';

COMMENT ON COLUMN "crews"."updated_at" IS 'Waktu diperbarui';

COMMENT ON COLUMN "crews"."created_at" IS 'Waktu dibuat';

COMMENT ON TABLE "rentals" IS 'Master data item rental/peralatan';

COMMENT ON COLUMN "rentals"."id" IS 'Primary key rental';

COMMENT ON COLUMN "rentals"."uuid" IS 'ID publik rental';

COMMENT ON COLUMN "rentals"."code" IS 'Kode rental';

COMMENT ON COLUMN "rentals"."name" IS 'Nama item rental';

COMMENT ON COLUMN "rentals"."description" IS 'Deskripsi rental';

COMMENT ON COLUMN "rentals"."price" IS 'Harga rental';

COMMENT ON COLUMN "rentals"."specs" IS 'Spesifikasi item';

COMMENT ON COLUMN "rentals"."images" IS 'Legacy kolom gambar; pertimbangkan pakai rental_images';

COMMENT ON COLUMN "rentals"."is_available" IS 'Status ketersediaan';

COMMENT ON COLUMN "rentals"."updated_at" IS 'Waktu diperbarui';

COMMENT ON COLUMN "rentals"."created_at" IS 'Waktu dibuat';

COMMENT ON TABLE "expendables" IS 'Master data expendables/habis pakai';

COMMENT ON COLUMN "expendables"."id" IS 'Primary key expendable';

